using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private StringFormatter _formatter = null!;

    [TestInitialize]
    public void Setup()
    {
        _formatter = new StringFormatter();
    }

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ContainsMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("My Post! #1");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetters_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("Azure DevOps Tips & Tricks");

        StringAssert.StartsWith(result, "azure");
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithWord_EndsWithThatWord()
    {
        var result = _formatter.GenerateSlug("Azure DevOps Tips & Tricks");

        StringAssert.EndsWith(result, "tricks");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_WithDefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_WithEuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(9.50m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_EndsWithCents()
    {
        var result = _formatter.FormatCurrency(49.95m);

        StringAssert.EndsWith(result, ".95");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsSymbolWithZero()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

